308→export function handleChainStream(
309→  data: { chunk?: Record<string, unknown> },
310→  node: ENodeName | undefined,
311→  subagent?: StreamSubagentInfo,
312→): IGraphEvent | undefined {
313→  const interrupts = data.chunk?.__interrupt__;
314→  if (!Array.isArray(interrupts) || interrupts.length === 0) {
315→    return undefined;
316→  }
317→
318→  const interrupt = interrupts[0] as { id?: string; value?: unknown };
319→  if (!interrupt?.value || typeof interrupt.value !== 'object') {
320→    return undefined;
321→  }
322→
323→  const payload = interrupt.value as IAskUserPayload;
324→  const payloadNode = payload.agent && TalkableAgents.includes(payload.agent) ? payload.agent : node;
325→  log(`ask-user interrupt: ${JSON.stringify(payload)}`);
326→  return makeEvent('interrupt', payloadNode, { interruptId: interrupt.id, ...payload }, subagent);
327→}
