351→export function handleToolEnd(
352→  runId: string,
353→  name: string,
354→  data: { output: { artifact: unknown; content: unknown } },
355→  node: ENodeName | undefined,
356→  subagent?: StreamSubagentInfo,
357→): IGraphEvent | undefined {
358→  if (name === EToolName.AskUser) {
359→    return undefined;
360→  }
361→
362→  const { artifact, content } = data.output;
363→
364→  if (artifact instanceof Error) {
365→    log(`tool-call-result(${name}).error: ${artifact.message}`);
366→  } else {
367→    log(`tool-call-result(${name}).artifact: ${tryJSONStringify(artifact) ?? 'undefined'}`);
368→  }
369→  log(`tool-call-result(${name}).content: ${content}`);
370→
371→  const output = resolveToolOutput(artifact, content);
372→  const toolError = extractToolError(artifact) ?? extractToolError(output);
373→  const outputStr = artifact instanceof Error
374→    ? (artifact as Error).message
375→    : toolError ?? (typeof output === 'string' ? output : tryJSONStringify(output) ?? '');
376→  const outputLength = outputStr.length;
377→  const summarizedOutput = shouldSummarizeToolCallResult(name)
378→    ? summarizeToolCallResult(outputStr)
379→    : outputStr;
380→
381→  return makeEvent('tool-call-result', node, {
382→    id: runId,
383→    name,
384→    outputLength,
385→    ...(artifact instanceof Error || toolError
386→      ? { error: summarizedOutput }
387→      : { output: shouldSummarizeToolCallResult(name) ? summarizedOutput : output }),
388→  }, subagent);
389→}
390→
391→export function handleChainError(
392→  name: string,
393→  data: { error?: unknown },
394→  node: ENodeName | undefined,
395→  subagent?: StreamSubagentInfo,
396→): IGraphEvent | undefined {
397→  if (!node || !(TalkableAgents as string[]).includes(name)) return undefined;
398→  const message = extractToolError(data.error) ?? tryJSONStringify(data.error) ?? 'Agent execution failed';
399→  log(`agent-error: ${name} - ${message}`);
400→  return makeEvent('agent-end', node, { name, error: message }, subagent);
401→}
402→
403→export function handleChatModelError(
404→  node: ENodeName | undefined,
405→  data: { error?: unknown },
406→  subagent?: StreamSubagentInfo,
407→): IGraphEvent | undefined {
408→  const message = extractToolError(data.error) ?? tryJSONStringify(data.error) ?? 'Model invocation failed';
409→  log(`chat-error: ${node} - ${message}`);
410→  return makeEvent('assistant-end', node, { node, error: message }, subagent);
411→}
412→
413→export function handleToolError(
414→  runId: string,
415→  name: string,
416→  data: { error?: unknown },
417→  node: ENodeName | undefined,
418→  subagent?: StreamSubagentInfo,
419→): IGraphEvent | undefined {
420→  if (name === EToolName.AskUser) {
421→    return undefined;
422→  }
423→
424→  const message = extractToolError(data.error) ?? tryJSONStringify(data.error) ?? 'Tool execution failed';
425→  log(`tool-call-result(${name}).error: ${message}`);
426→  const summarizedMessage = shouldSummarizeToolCallResult(name)
427→    ? summarizeToolCallResult(message)
428→    : message;
429→
430→  return makeEvent('tool-call-result', node, {
431→    id: runId,
432→    name,
433→    outputLength: message.length,
434→    error: summarizedMessage,
435→  }, subagent);
436→}
437→
438→function buildSubagentInfo(name: string, data: Record<string, unknown>, metadata: StreamMetadata | undefined, state: ToolInputState) {
439→  if (name === TASK_TOOL_NAME) {
440→    registerTaskSubagentNamespace(name, data, metadata, state);
441→  }
442→
443→  return resolveSubagentInfo(metadata, state);
444→}
445→
446→export function dispatchStreamEvent(
447→  event: string,
448→  ctx: StreamContext,
449→  state: ToolInputState,
450→): IGraphEvent | undefined {
451→  const { run_id, name, data, node, metadata } = ctx;
452→  const subagent = buildSubagentInfo(name, data, metadata, state);
453→
454→  // 默认关闭流式调试，避免敏感数据落盘与同步 IO 阻塞。
455→  writeStreamDebugLog(event, name, node, data);
456→
457→  switch (event) {
458→    case 'on_chain_start':
459→      return handleChainStart(name, node, subagent);
460→    case 'on_chain_end':
461→      return handleChainEnd(name, node, subagent);
462→    case 'on_chain_error':
463→      return handleChainError(name, data as { error?: unknown }, node, subagent);
464→    case 'on_chat_model_start':
465→      return handleChatModelStart(node, subagent);
466→    case 'on_chat_model_end':
467→      return handleChatModelEnd(node, data, subagent);
468→    case 'on_chat_model_error':
469→      return handleChatModelError(node, data as { error?: unknown }, subagent);
470→    case 'on_chat_model_stream':
471→      return handleChatModelStream(data as { chunk: unknown }, node, state, subagent);
472→    case 'on_chain_stream':
473→      return handleChainStream(data as { chunk?: Record<string, unknown> }, node, subagent);
474→    case 'on_tool_start':
475→      return handleToolStart(
476→        run_id,
477→        name,
478→        data as { input: { input: string } },
479→        node,
480→        state,
481→        subagent,
482→      );
483→    case 'on_tool_end':
484→      return handleToolEnd(
485→        run_id,
486→        name,
487→        data as { output: { artifact: unknown; content: unknown } },
488→        node,
489→        subagent,
490→      );
491→    case 'on_tool_error':
492→      return handleToolError(
493→        run_id,
494→        name,
495→        data as { error?: unknown },
496→        node,
497→        subagent,
498→      );
499→    default:
500→      return undefined;
501→  }
502→}
