135→export default async function createSimpleDeepAgent(
136→  model: BaseLanguageModel,
137→  conversationId: string,
138→  sandboxManager: ConversationSandboxManager,
139→): Promise<ReturnType<typeof createDeepAgent>> {
140→  const session = await sandboxManager.getConversationSandbox(conversationId);
141→  const client = new MultiServerMCPClient({
142→    grafana: {
143→      transport: 'sse',
144→      url: configSchema.GRAFANA_MCP_URL!,
145→    },
146→  });
147→
148→  // 过滤，只剩下
149→  const FILTER_TOOLS = ['search_dashboards', 'list_datasources', 'get_dashboard_panel_queries', 'query_prometheus', 'list_prometheus_label_names', 'generate_deeplink', 'get_dashboard_by_uid'];
150→  const allMcpTools = (await client.getTools()).filter(tool => FILTER_TOOLS.includes(tool.name)) as DynamicStructuredTool[]
151→
152→  const middleware = [
153→    createToolErrorMiddleware(),
154→    vfsRelativePathMiddleware,
155→    createStrictToolEvictionMiddleware(session.backend),
156→  ]
157→
158→  return createDeepAgent({
159→    model: model,
160→    tools: allMcpTools,
161→    middleware,
162→    backend: session.backend,
163→    checkpointer: memory,
164→    skills: [SANDBOX_SKILLS_ROOT]
165→  });
166→}
